PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE articles (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  slug TEXT UNIQUE NOT NULL,
  title TEXT NOT NULL,
  excerpt TEXT,
  content TEXT NOT NULL,
  category TEXT,
  tags TEXT DEFAULT '[]',
  image_url TEXT,
  seo_title TEXT,
  seo_description TEXT,
  status TEXT DEFAULT 'draft',
  author TEXT DEFAULT 'admin',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE faqs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  question TEXT NOT NULL,
  answer TEXT NOT NULL,
  category TEXT NOT NULL,
  sort_order INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
, is_homepage INTEGER DEFAULT 0);
CREATE TABLE categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  hero_title TEXT,
  hero_subtitle TEXT,
  description TEXT DEFAULT '[]',
  what_you_can_drive TEXT DEFAULT '[]',
  conditions TEXT DEFAULT '[]',
  documents TEXT DEFAULT '[]',
  duration_info TEXT,
  info_note TEXT,
  testimonials TEXT DEFAULT '[]',
  image_url TEXT,
  seo_title TEXT,
  seo_description TEXT,
  sort_order INTEGER DEFAULT 0,
  updated_at TEXT DEFAULT (datetime('now'))
, graduate_images TEXT DEFAULT '[]');
CREATE TABLE instructors (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  role TEXT,
  categories TEXT,
  experience TEXT,
  hours TEXT,
  students TEXT,
  tags TEXT DEFAULT '[]',
  image_url TEXT,
  sort_order INTEGER DEFAULT 0,
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE gallery_images (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  image_url TEXT NOT NULL,
  album TEXT DEFAULT 'general',
  caption TEXT,
  sort_order INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
, is_cover INTEGER DEFAULT 0, media_type TEXT DEFAULT 'image', video_url TEXT, layout_size TEXT DEFAULT 'normal');
CREATE TABLE leads (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  phone TEXT NOT NULL,
  category TEXT,
  message TEXT,
  status TEXT DEFAULT 'nou',
  source TEXT DEFAULT 'website',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, email TEXT);
CREATE TABLE uploads (id INTEGER PRIMARY KEY AUTOINCREMENT, filename TEXT NOT NULL, mime_type TEXT NOT NULL, data BLOB NOT NULL, created_at TEXT DEFAULT (datetime('now')));
CREATE TABLE settings (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL
);
CREATE TABLE cars (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  model TEXT NOT NULL,
  tag TEXT NOT NULL,
  image_url TEXT,
  sort_order INTEGER DEFAULT 0
);
CREATE TABLE testimonials (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  text TEXT NOT NULL,
  rating INTEGER DEFAULT 5,
  image_url TEXT,
  source TEXT DEFAULT 'Google',
  sort_order INTEGER DEFAULT 0
);
DELETE FROM sqlite_sequence;
